import os
from google.cloud import storage

def process_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']

    # Extract filename and conversion options from event metadata
    filename, extension = os.path.splitext(file_name)
    if 'convert_options' in event:
        convert_options = event['convert_options']
    else:
        convert_options = '-resize 800x600'

    # Use subprocess.call() with event parameters to run convert command
    cmd = f"gmagick {convert_options} gs://{bucket_name}/{file_name}{extension} gs://{bucket_name}/processed/{filename}_processed{extension}"
